import React, { useState, useEffect } from 'react';

const App = () => {
  const [accessToken, setAccessToken] = useState(localStorage.getItem('accessToken'));
  const [authCode, setAuthCode] = useState('');
  const [error, setError] = useState('');

  const CLIENT_ID = 'your_client_id';
  const REDIRECT_URI = 'https://your-app.com/callback';
  const AUTHORIZATION_ENDPOINT = 'https://authorization-server.com/auth';
  const TOKEN_ENDPOINT = 'https://token-server.com/token';

  useEffect(() => {
    if (accessToken) {
      fetch('https://api.yourapp.com/data', {
        headers: { Authorization: `Bearer ${accessToken}` }
      })
      .then(response => response.json())
      .then(data => console.log('Data:', data))
      .catch(error => console.error('Error fetching data:', error));
    }
  }, [accessToken]);

  const handleLogin = () => {
    const authUrl = `${AUTHORIZATION_ENDPOINT}?response_type=code&client_id=${CLIENT_ID}&redirect_uri=${encodeURIComponent(REDIRECT_URI)}`;
    window.location.href = authUrl;
  };

  const handleCallback = () => {
    const urlParams = new URLSearchParams(window.location.search);
    const code = urlParams.get('code');
    if (code) {
      setAuthCode(code);
      exchangeAuthorizationCodeForAccessToken(code);
    } else {
      setError('Failed to retrieve authorization code.');
    }
  };

  const exchangeAuthorizationCodeForAccessToken = async (code) => {
    try {
      const response = await fetch(TOKEN_ENDPOINT, {
        method: 'POST',
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
        body: `grant_type=authorization_code&client_id=${CLIENT_ID}&redirect_uri=${encodeURIComponent(REDIRECT_URI)}&code=${code}`
      });

      if (!response.ok) {
        throw new Error('Failed to exchange authorization code for access token.');
      }

      const data = await response.json();
      setAccessToken(data.access_token);
      localStorage.setItem('accessToken', data.access_token);
    } catch (error) {
      setError(error.message);
    }
  };

  return (
    <div>
      {error && <p>{error}</p>}
      {!accessToken ? (
        <button onClick={handleLogin}>Login with OAuth</button>
      ) : (
        <div>
          <h1>Welcome, you are authenticated!</h1>
          {/* Your application content goes here */}
        </div>
      )}
    </div>
  );
};

export default App;